import{_ as a,p as e,q as s,a1 as n}from"./framework-5866ffd3.js";const d={},r=n(`<h1 id="gpasswd" tabindex="-1"><a class="header-anchor" href="#gpasswd" aria-hidden="true">#</a> gpasswd</h1><p>Linux下工作组文件的管理工具</p><h2 id="补充说明" tabindex="-1"><a class="header-anchor" href="#补充说明" aria-hidden="true">#</a> 补充说明</h2><p><strong>gpasswd命令</strong> 是Linux下工作组文件<code>/etc/group</code>和<code>/etc/gshadow</code>管理工具。</p><h3 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>gpasswd<span class="token punctuation">(</span>选项<span class="token punctuation">)</span><span class="token punctuation">(</span>参数<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="选项" tabindex="-1"><a class="header-anchor" href="#选项" aria-hidden="true">#</a> 选项</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>-a：添加用户到组；
-d：从组删除用户；
-A：指定管理员；
-M：指定组成员和-A的用途差不多；
-r：删除密码；
-R：限制用户登入组，只有组中的成员才可以用newgrp加入该组。
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h3><p>组：指定要管理的工作组。</p><h3 id="实例" tabindex="-1"><a class="header-anchor" href="#实例" aria-hidden="true">#</a> 实例</h3><p>如系统有个peter账户，该账户本身不是groupname群组的成员，使用newgrp需要输入密码即可。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>gpasswd groupname
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>让使用者暂时加入成为该组成员，之后peter建立的文件group也会是groupname。所以该方式可以暂时让peter建立文件时使用其他的组，而不是peter本身所在的组。</p><p>所以使用<code>gpasswd groupname</code>设定密码，就是让知道该群组密码的人可以暂时切换具备groupname群组功能的。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>gpasswd <span class="token parameter variable">-A</span> peter <span class="token function">users</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>这样peter就是users群组的管理员，就可以执行下面的操作:</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>gpasswd <span class="token parameter variable">-a</span> mary <span class="token function">users</span>
gpasswd <span class="token parameter variable">-a</span> allen <span class="token function">users</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>注意：添加用户到某一个组 可以使用<code>usermod -G group_name user_name</code>这个命令可以添加一个用户到指定的组，但是以前添加的组就会清空掉。</p><p>所以想要添加一个用户到一个组，同时保留以前添加的组时，请使用gpasswd这个命令来添加操作用户：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>gpasswd <span class="token parameter variable">-a</span> user_name group_name
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div>`,21),i=[r];function c(l,p){return e(),s("div",null,i)}const u=a(d,[["render",c],["__file","gpasswd.html.vue"]]);export{u as default};
